import { useState, useEffect } from "react";
import axios from "axios";
import "./../styles/Br_user.css";

const API_BASE = "http://localhost:5000/books";

export default function LibraryApp() {
  const [books, setBooks] = useState([]);
  const [borrowedBooks, setBorrowedBooks] = useState([]);
  const [search, setSearch] = useState("");

  useEffect(() => {
    fetchBooks();
    fetchBorrowedBooks();
  }, []);

  const fetchBooks = async () => {
    try {
      const response = await axios.get(API_BASE);
      setBooks(response.data.books);
    } catch (error) {
      console.error("Error fetching books", error);
    }
  };

  const fetchBorrowedBooks = async () => {
    try {
      const response = await axios.get(`${API_BASE}/borrowed`, {
        headers: { Authorization: `Bearer ${localStorage.getItem("token")}` },
      });
      setBorrowedBooks(response.data.books);
    } catch (error) {
      console.error("Error fetching borrowed books", error);
    }
  };

  const borrowBook = async (bookId) => {
    try {
      await axios.post(
        `${API_BASE}/borrow`,
        { book_id: bookId },
        { headers: { Authorization: `Bearer ${localStorage.getItem("token")}` } }
      );
      fetchBorrowedBooks();
    } catch (error) {
      console.error("Error borrowing book", error);
    }
  };

  const returnBook = async (bookId) => {
    try {
      await axios.put(
        `${API_BASE}/return/${bookId}`,
        {},
        { headers: { Authorization: `Bearer ${localStorage.getItem("token")}` } }
      );
      fetchBorrowedBooks();
    } catch (error) {
      console.error("Error returning book", error);
    }
  };

  return (
    <div className="library-container">
      <h1 className="library-title">Library Management</h1>

      {/* Search Bar */}
      <input
        className="library-input"
        type="text"
        placeholder="Search books..."
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />

      <h2 className="library-subtitle">Available Books</h2>
      <ul className="book-list">
        {books
          .filter((book) =>
            book.title.toLowerCase().includes(search.toLowerCase())
          )
          .map((book) => (
            <li key={book.id} className="book-item">
              {book.title} by {book.author}
              <button className="borrow-button" onClick={() => borrowBook(book.id)}>
                Borrow
              </button>
            </li>
          ))}
      </ul>

      <h2 className="library-subtitle">Borrowed Books</h2>
      <ul className="book-list">
        {borrowedBooks.map((book) => (
          <li key={book.id} className="book-item">
            {book.title} by {book.author}
            <button className="return-button" onClick={() => returnBook(book.id)}>
              Return
            </button>
          </li>
        ))}
      </ul>
    </div>
  );
}
